--
-- Triggers `blockchain_transactions`
--
DELIMITER $$
CREATE TRIGGER `trg_blockchain_tx_baseline_hash_bi` BEFORE INSERT ON `blockchain_transactions` FOR EACH ROW BEGIN
  SET NEW.`tx_row_hash_original` = NEW.`tx_row_hash`;
  SET NEW.`original_tx_hash` = NEW.`blockchain_tx_hash`;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_blockchain_tx_baseline_hash_bu` BEFORE UPDATE ON `blockchain_transactions` FOR EACH ROW BEGIN
  SET NEW.`tx_row_hash_original` = COALESCE(
    OLD.`tx_row_hash_original`,
    NEW.`tx_row_hash`,
    OLD.`tx_row_hash`
  );

  SET NEW.`original_tx_hash` = COALESCE(
    OLD.`original_tx_hash`,
    OLD.`blockchain_tx_hash`,
    NEW.`blockchain_tx_hash`
  );
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_blockchain_tx_hash_bi` BEFORE INSERT ON `blockchain_transactions` FOR EACH ROW SET NEW.`tx_row_hash` = LOWER(SHA2(
  CONCAT_WS('|',
    'id=', COALESCE(NEW.`id`, -1),
    'transaction_type=', COALESCE(NEW.`transaction_type`, ''),
    'related_id=', COALESCE(NEW.`related_id`, -1),
    'blockchain_tx_hash=', COALESCE(NEW.`blockchain_tx_hash`, ''),
    'block_number=', COALESCE(NEW.`block_number`, -1),
    'gas_used=', COALESCE(NEW.`gas_used`, -1),
    'gas_price=', COALESCE(NEW.`gas_price`, -1),
    'status=', COALESCE(NEW.`status`, ''),
    'confirmation_blocks=', COALESCE(NEW.`confirmation_blocks`, 0),
    'created_at=', COALESCE(DATE_FORMAT(NEW.`created_at`, '%Y-%m-%d %H:%i:%s'), ''),
    'confirmed_at=', COALESCE(DATE_FORMAT(NEW.`confirmed_at`, '%Y-%m-%d %H:%i:%s'), ''),
    'error_message=', COALESCE(NEW.`error_message`, '')
  ), 256))
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_blockchain_tx_hash_bu` BEFORE UPDATE ON `blockchain_transactions` FOR EACH ROW SET NEW.`tx_row_hash` = LOWER(SHA2(
  CONCAT_WS('|',
    'id=', COALESCE(NEW.`id`, -1),
    'transaction_type=', COALESCE(NEW.`transaction_type`, ''),
    'related_id=', COALESCE(NEW.`related_id`, -1),
    'blockchain_tx_hash=', COALESCE(NEW.`blockchain_tx_hash`, ''),
    'block_number=', COALESCE(NEW.`block_number`, -1),
    'gas_used=', COALESCE(NEW.`gas_used`, -1),
    'gas_price=', COALESCE(NEW.`gas_price`, -1),
    'status=', COALESCE(NEW.`status`, ''),
    'confirmation_blocks=', COALESCE(NEW.`confirmation_blocks`, 0),
    'created_at=', COALESCE(DATE_FORMAT(NEW.`created_at`, '%Y-%m-%d %H:%i:%s'), ''),
    'confirmed_at=', COALESCE(DATE_FORMAT(NEW.`confirmed_at`, '%Y-%m-%d %H:%i:%s'), ''),
    'error_message=', COALESCE(NEW.`error_message`, '')
  ), 256))
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_blockchain_tx_payload_ai` AFTER INSERT ON `blockchain_transactions` FOR EACH ROW INSERT INTO `payload_history` (
  `donation_id`, `don_refnum`, `payload_hash`, `payload_data`,
  `previous_hash`, `change_type`, `change_reason`, `changed_by`, `created_at`
)
SELECT
  NEW.`related_id`,
  d.`don_refnum`,
  NEW.`tx_row_hash`,
  JSON_OBJECT(
    'source', 'blockchain_transactions',
    'tx_id', NEW.`id`,
    'transaction_type', NEW.`transaction_type`,
    'related_id', NEW.`related_id`,
    'blockchain_tx_hash', NEW.`blockchain_tx_hash`,
    'block_number', NEW.`block_number`,
    'gas_used', NEW.`gas_used`,
    'gas_price', NEW.`gas_price`,
    'status', NEW.`status`,
    'confirmation_blocks', NEW.`confirmation_blocks`,
    'created_at', DATE_FORMAT(NEW.`created_at`, '%Y-%m-%d %H:%i:%s'),
    'confirmed_at', DATE_FORMAT(NEW.`confirmed_at`, '%Y-%m-%d %H:%i:%s'),
    'error_message', NEW.`error_message`
  ),
  NULL,
  CASE
    WHEN NEW.`transaction_type` = 'donation' THEN 'created'
    ELSE 'created'
  END,
  'blockchain tx row created',
  CASE
    WHEN d.`don_donorid` > 0
      AND EXISTS (SELECT 1 FROM `users` WHERE `id` = d.`don_donorid`)
    THEN d.`don_donorid`
    ELSE NULL
  END,
  NOW()
FROM `donations` d
WHERE NEW.`transaction_type` = 'donation'
  AND d.`don_id` = NEW.`related_id`
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_blockchain_tx_payload_au` AFTER UPDATE ON `blockchain_transactions` FOR EACH ROW INSERT INTO `payload_history` (
  `donation_id`, `don_refnum`, `payload_hash`, `payload_data`,
  `previous_hash`, `change_type`, `change_reason`, `changed_by`, `created_at`
)
SELECT
  NEW.`related_id`,
  d.`don_refnum`,
  NEW.`tx_row_hash`,
  JSON_OBJECT(
    'source', 'blockchain_transactions',
    'tx_id', NEW.`id`,
    'transaction_type', NEW.`transaction_type`,
    'related_id', NEW.`related_id`,
    'blockchain_tx_hash', NEW.`blockchain_tx_hash`,
    'block_number', NEW.`block_number`,
    'gas_used', NEW.`gas_used`,
    'gas_price', NEW.`gas_price`,
    'status', NEW.`status`,
    'confirmation_blocks', NEW.`confirmation_blocks`,
    'created_at', DATE_FORMAT(NEW.`created_at`, '%Y-%m-%d %H:%i:%s'),
    'confirmed_at', DATE_FORMAT(NEW.`confirmed_at`, '%Y-%m-%d %H:%i:%s'),
    'error_message', NEW.`error_message`
  ),
  OLD.`tx_row_hash`,
  'updated',
  'blockchain tx row hash changed',
  CASE
    WHEN d.`don_donorid` > 0
      AND EXISTS (SELECT 1 FROM `users` WHERE `id` = d.`don_donorid`)
    THEN d.`don_donorid`
    ELSE NULL
  END,
  NOW()
FROM `donations` d
WHERE NEW.`transaction_type` = 'donation'
  AND NOT (OLD.`tx_row_hash` <=> NEW.`tx_row_hash`)
  AND d.`don_id` = NEW.`related_id`
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_blockchain_tx_rowhash_bi` BEFORE INSERT ON `blockchain_transactions` FOR EACH ROW BEGIN
  SET NEW.tx_row_hash = fn_blockchain_tx_row_hash_v1(
    NEW.id,
    NEW.transaction_type,
    NEW.related_id,
    NEW.blockchain_tx_hash,
    NEW.block_number,
    NEW.gas_used,
    NEW.gas_price,
    NEW.status,
    NEW.confirmation_blocks,
    NEW.created_at,
    NEW.confirmed_at,
    NEW.error_message
  );
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_blockchain_tx_rowhash_bu` BEFORE UPDATE ON `blockchain_transactions` FOR EACH ROW BEGIN
  SET NEW.tx_row_hash = fn_blockchain_tx_row_hash_v1(
    NEW.id,
    NEW.transaction_type,
    NEW.related_id,
    NEW.blockchain_tx_hash,
    NEW.block_number,
    NEW.gas_used,
    NEW.gas_price,
    NEW.status,
    NEW.confirmation_blocks,
    NEW.created_at,
    NEW.confirmed_at,
    NEW.error_message
  );
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_blockchain_tx_tamper_bi` BEFORE INSERT ON `blockchain_transactions` FOR EACH ROW BEGIN
  SET NEW.`is_tampered` = 0;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_blockchain_tx_tamper_bu` BEFORE UPDATE ON `blockchain_transactions` FOR EACH ROW BEGIN
  DECLARE changed_core TINYINT(1) DEFAULT 0;
  DECLARE initial_blockchain_write TINYINT(1) DEFAULT 0;

  SET changed_core = (
    NOT (OLD.`transaction_type` <=> NEW.`transaction_type`) OR
    NOT (OLD.`related_id` <=> NEW.`related_id`)
  );

  SET initial_blockchain_write = (
    COALESCE(OLD.`original_tx_hash`, '') = ''
    AND changed_core = 0
    AND (
      NOT (OLD.`blockchain_tx_hash` <=> NEW.`blockchain_tx_hash`) OR
      NOT (OLD.`block_number` <=> NEW.`block_number`) OR
      NOT (OLD.`gas_used` <=> NEW.`gas_used`) OR
      NOT (OLD.`gas_price` <=> NEW.`gas_price`) OR
      NOT (OLD.`status` <=> NEW.`status`) OR
      NOT (OLD.`confirmation_blocks` <=> NEW.`confirmation_blocks`) OR
      NOT (OLD.`confirmed_at` <=> NEW.`confirmed_at`) OR
      NOT (OLD.`error_message` <=> NEW.`error_message`) OR
      NOT (OLD.`original_tx_hash` <=> NEW.`original_tx_hash`)
    )
  );

  IF COALESCE(OLD.`is_tampered`, 0) = 1 THEN
    SET NEW.`is_tampered` = 1;
  ELSEIF initial_blockchain_write = 1 THEN
    SET NEW.`is_tampered` = 0;
  ELSEIF changed_core = 1 THEN
    SET NEW.`is_tampered` = 1;
  ELSE
    SET NEW.`is_tampered` = COALESCE(OLD.`is_tampered`, 0);
  END IF;
END
$$
DELIMITER ;

