--
-- Stand-in structure for view `blockchain_transaction_summary`
-- (See below for the actual view)
--
CREATE TABLE `blockchain_transaction_summary` (
`transaction_type` enum('donation','fundraiser_creation','fundraiser_update')
,`status` enum('pending','confirmed','failed')
,`transaction_count` bigint(21)
,`total_gas_used` decimal(41,0)
,`avg_gas_used` decimal(23,4)
,`earliest_transaction` datetime
,`latest_transaction` datetime
);

-- --------------------------------------------------------

--
-- Table structure for table `blockchain_verification_logs`
--

CREATE TABLE `blockchain_verification_logs` (
  `id` int(11) NOT NULL,
  `transaction_hash` varchar(66) NOT NULL,
  `verification_type` enum('donation','fundraiser','general') NOT NULL,
  `verification_status` enum('success','failed','pending') NOT NULL,
  `verification_method` enum('smart_contract','api','manual') NOT NULL,
  `verification_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`verification_data`)),
  `error_message` text DEFAULT NULL,
  `verified_by` int(11) DEFAULT NULL COMMENT 'User ID who performed verification',
  `created_at` datetime NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- --------------------------------------------------------

--
-- Table structure for table `donations`
--

CREATE TABLE `donations` (
  `don_id` int(11) NOT NULL,
  `fund_id` int(11) NOT NULL,
  `don_donorid` int(11) NOT NULL,
  `don_donorname` varchar(80) NOT NULL,
  `don_receiver` varchar(80) NOT NULL,
  `don_paymethod` varchar(50) NOT NULL,
  `don_amount` decimal(12,2) NOT NULL,
  `don_refnum` varchar(80) NOT NULL,
  `don_status` varchar(50) NOT NULL,
  `don_date` datetime NOT NULL,
  `don_notes` text DEFAULT NULL,
  `blockchain_tx_hash` varchar(66) DEFAULT NULL COMMENT 'Blockchain transaction hash',
  `block_number` bigint(20) DEFAULT NULL COMMENT 'Block number where transaction was recorded',
  `gas_used` bigint(20) DEFAULT NULL COMMENT 'Gas used for the transaction',
  `verification_status` enum('pending','verified','failed') DEFAULT 'pending' COMMENT 'Blockchain verification status',
  `verification_date` datetime DEFAULT NULL COMMENT 'When the transaction was verified on blockchain',
  `donor_wallet_address` varchar(42) DEFAULT NULL COMMENT 'Donor wallet address for blockchain transactions',
  `recorded_by_admin` tinyint(1) DEFAULT 0,
  `donation_row_hash` char(64) DEFAULT NULL,
  `is_tampered` tinyint(1) NOT NULL DEFAULT 0,
  `donation_row_hash_original` char(64) DEFAULT NULL,
  `original_tx_hash` varchar(66) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

