--
-- Triggers `donations`
--
DELIMITER $$
CREATE TRIGGER `trg_donation_baseline_hash_bi` BEFORE INSERT ON `donations` FOR EACH ROW BEGIN
  SET NEW.`donation_row_hash_original` = NEW.`donation_row_hash`;
  SET NEW.`original_tx_hash` = NEW.`blockchain_tx_hash`;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_donation_baseline_hash_bu` BEFORE UPDATE ON `donations` FOR EACH ROW BEGIN
  SET NEW.`donation_row_hash_original` = COALESCE(
    OLD.`donation_row_hash_original`,
    NEW.`donation_row_hash`,
    OLD.`donation_row_hash`
  );

  SET NEW.`original_tx_hash` = COALESCE(
    OLD.`original_tx_hash`,
    OLD.`blockchain_tx_hash`,
    NEW.`blockchain_tx_hash`
  );
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_donation_payload_hash_ai` AFTER INSERT ON `donations` FOR EACH ROW BEGIN
  INSERT INTO `payload_history` (
    `donation_id`, `don_refnum`, `payload_hash`, `payload_data`,
    `previous_hash`, `change_type`, `change_reason`, `changed_by`, `created_at`
  )
  VALUES (
    NEW.`don_id`,
    NEW.`don_refnum`,
    NEW.`donation_row_hash`,
    IF(
      NEW.`don_notes` IS NULL
      OR NEW.`don_notes` = ''
      OR JSON_VALID(NEW.`don_notes`) = 0,
      JSON_OBJECT(),
      NEW.`don_notes`
    ),
    NULL,
    'created',
    'Initial row hash capture',
    CASE
      WHEN NEW.`don_donorid` > 0 AND EXISTS (SELECT 1 FROM `users` WHERE `id` = NEW.`don_donorid`)
      THEN NEW.`don_donorid`
      ELSE NULL
    END,
    NOW()
  );
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_donation_payload_hash_au` AFTER UPDATE ON `donations` FOR EACH ROW BEGIN
  IF NOT (OLD.`donation_row_hash` <=> NEW.`donation_row_hash`) THEN
    INSERT INTO `payload_history` (
      `donation_id`, `don_refnum`, `payload_hash`, `payload_data`,
    `previous_hash`, `change_type`, `change_reason`, `changed_by`, `created_at`
  )
  VALUES (
      NEW.`don_id`,
      NEW.`don_refnum`,
      NEW.`donation_row_hash`,
      IF(
        NEW.`don_notes` IS NULL
        OR NEW.`don_notes` = ''
        OR JSON_VALID(NEW.`don_notes`) = 0,
        JSON_OBJECT(),
        NEW.`don_notes`
      ),
      OLD.`donation_row_hash`,
      'updated',
      'Donation row hash changed',
      CASE
        WHEN NEW.`don_donorid` > 0 AND EXISTS (SELECT 1 FROM `users` WHERE `id` = NEW.`don_donorid`)
        THEN NEW.`don_donorid`
        ELSE NULL
      END,
      NOW()
    );
  END IF;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_donation_rowhash_bi` BEFORE INSERT ON `donations` FOR EACH ROW BEGIN
  SET NEW.donation_row_hash = fn_donation_row_hash_v1(
    NEW.don_id,
    NEW.fund_id,
    NEW.don_donorid,
    NEW.don_donorname,
    NEW.don_receiver,
    NEW.don_paymethod,
    NEW.don_amount,
    NEW.don_refnum,
    NEW.don_status,
    NEW.don_date,
    NEW.don_notes,
    NEW.blockchain_tx_hash,
    NEW.block_number,
    NEW.gas_used,
    NEW.verification_status,
    NEW.verification_date,
    NEW.donor_wallet_address,
    NEW.recorded_by_admin
  );
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_donation_rowhash_bu` BEFORE UPDATE ON `donations` FOR EACH ROW BEGIN
  SET NEW.donation_row_hash = fn_donation_row_hash_v1(
    NEW.don_id,
    NEW.fund_id,
    NEW.don_donorid,
    NEW.don_donorname,
    NEW.don_receiver,
    NEW.don_paymethod,
    NEW.don_amount,
    NEW.don_refnum,
    NEW.don_status,
    NEW.don_date,
    NEW.don_notes,
    NEW.blockchain_tx_hash,
    NEW.block_number,
    NEW.gas_used,
    NEW.verification_status,
    NEW.verification_date,
    NEW.donor_wallet_address,
    NEW.recorded_by_admin
  );
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_donation_tamper_bi` BEFORE INSERT ON `donations` FOR EACH ROW BEGIN
  SET NEW.`is_tampered` = 0;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_donation_tamper_bu` BEFORE UPDATE ON `donations` FOR EACH ROW BEGIN
  DECLARE changed_core TINYINT(1) DEFAULT 0;
  DECLARE initial_blockchain_write TINYINT(1) DEFAULT 0;

  SET changed_core = (
    NOT (OLD.`fund_id` <=> NEW.`fund_id`) OR
    NOT (OLD.`don_donorid` <=> NEW.`don_donorid`) OR
    NOT (OLD.`don_donorname` <=> NEW.`don_donorname`) OR
    NOT (OLD.`don_paymethod` <=> NEW.`don_paymethod`) OR
    NOT (OLD.`don_amount` <=> NEW.`don_amount`) OR
    NOT (OLD.`don_refnum` <=> NEW.`don_refnum`) OR
    NOT (OLD.`don_date` <=> NEW.`don_date`) OR
    NOT (OLD.`donor_wallet_address` <=> NEW.`donor_wallet_address`) OR
    NOT (OLD.`recorded_by_admin` <=> NEW.`recorded_by_admin`)
  );

  SET initial_blockchain_write = (
    COALESCE(OLD.`original_tx_hash`, '') = ''
    AND changed_core = 0
    AND (
      NOT (OLD.`blockchain_tx_hash` <=> NEW.`blockchain_tx_hash`) OR
      NOT (OLD.`block_number` <=> NEW.`block_number`) OR
      NOT (OLD.`gas_used` <=> NEW.`gas_used`) OR
      NOT (OLD.`verification_status` <=> NEW.`verification_status`) OR
      NOT (OLD.`verification_date` <=> NEW.`verification_date`) OR
      NOT (OLD.`original_tx_hash` <=> NEW.`original_tx_hash`)
    )
  );

  IF COALESCE(OLD.`is_tampered`, 0) = 1 THEN
    SET NEW.`is_tampered` = 1;
  ELSEIF initial_blockchain_write = 1 THEN
    SET NEW.`is_tampered` = 0;
  ELSEIF changed_core = 1 THEN
    SET NEW.`is_tampered` = 1;
  ELSE
    SET NEW.`is_tampered` = COALESCE(OLD.`is_tampered`, 0);
  END IF;
END
$$
DELIMITER ;

