CREATE TABLE `fundraisers` (
  `fund_id` int(11) NOT NULL,
  `fund_title` varchar(80) NOT NULL,
  `fund_desc` text NOT NULL,
  `fund_category` varchar(60) NOT NULL,
  `fund_img` longblob DEFAULT NULL,
  `fund_beneficiary` varchar(100) DEFAULT NULL,
  `fund_goalamount` decimal(12,2) NOT NULL,
  `fund_link` varchar(80) DEFAULT NULL,
  `fund_status` varchar(50) NOT NULL,
  `fund_startdate` datetime NOT NULL,
  `fund_enddate` date DEFAULT NULL,
  `fund_creatorid` int(11) NOT NULL DEFAULT 202504,
  `blockchain_fund_id` int(11) DEFAULT NULL COMMENT 'Blockchain fundraiser ID',
  `blockchain_tx_hash` varchar(66) DEFAULT NULL COMMENT 'Blockchain transaction hash for fundraiser creation',
  `blockchain_verified` tinyint(1) DEFAULT 0 COMMENT 'Whether fundraiser is verified on blockchain',
  `creator_wallet_address` varchar(42) DEFAULT NULL COMMENT 'Creator wallet address'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

