INSERT INTO `fundraisers` (`fund_id`, `fund_title`, `fund_desc`, `fund_category`, `fund_img`, `fund_beneficiary`, `fund_goalamount`, `fund_link`, `fund_status`, `fund_startdate`, `fund_enddate`, `fund_creatorid`, `blockchain_fund_id`, `blockchain_tx_hash`, `blockchain_verified`, `creator_wallet_address`) VALUES
(20252601, 'School Supplies for Kids from Flooded Areas in Barangay Linga', 'In the aftermath of devastating floods that have affected Barangay Linga, many families are struggling to recover from the damage inflicted on their homes and communities. The floods have not only displaced residents but have also destroyed vital resources, including educational materials that children rely on for their schooling. \r\n\r\nAs students prepare to return to school, the need for essential supplies such as notebooks, pencils, backpacks, and other learning materials has become a pressing concern. Many families, already facing financial strain due to the disaster, are unable to afford these basic items, which are crucial for their children’s education and future. Without proper supplies, students are at risk of falling behind in their studies, further exacerbating the challenges faced by the community.\r\n\r\nThis fundraiser aims to raise ₱50,000 to provide school supplies for the children affected by the floods. The funds will be used to purchase necessary educational materials that will help restore a sense of normalcy and support the learning process for these children. By contributing to this cause, donors will play a vital role in ensuring that students have the tools they need to succeed in their education, fostering hope and resilience in a community working to rebuild after disaster. \r\n\r\nEvery contribution, no matter the size, will make a significant impact on the lives of these children, helping them to focus on their studies and regain a sense of stability amid the ongoing recovery efforts in Barangay Linga.', 'Disaster Relief', , 'Someone else', '50000.00', 'generated-link', 'Completed', '2025-09-20 11:23:54', NULL, 202502, NULL, NULL, 0, NULL);
INSERT INTO `fundraisers` (`fund_id`, `fund_title`, `fund_desc`, `fund_category`, `fund_img`, `fund_beneficiary`, `fund_goalamount`, `fund_link`, `fund_status`, `fund_startdate`, `fund_enddate`, `fund_creatorid`, `blockchain_fund_id`, `blockchain_tx_hash`, `blockchain_verified`, `creator_wallet_address`) VALUES
(20252602, 'Medical Support for Baby Liam', 'Baby Liam, only 8 months old, has been diagnosed with congenital heart disease that requires urgent surgery. His parents, both minimum wage earners, cannot afford the high medical costs for hospital care, medications, and the surgery itself. The family has already sold belongings and borrowed money, but it is still far from enough. This fundraiser is organized to help Baby Liam receive the treatment he desperately needs. Every donation will go directly to covering hospital bills, doctor’s fees, and medications. Without this procedure, his condition may worsen, putting his young life in grave danger. We believe that no parent should lose a child simply because of financial limitations. Through your kindness, we can extend hope and healing to Baby Liam. Let us come together as a community to give this little boy a fighting chance at life. Your prayers and donations will truly mean the world to him and his family.', 'Medical', NULL, 'Baby Liam (8 months old)', '150000.00', NULL, 'Active', '2025-08-25 14:30:00', NULL, 202504, NULL, NULL, 0, NULL),
(20252603, 'Livelihood Kits for Single Mothers', 'In our community, many single mothers are struggling to provide for their families. They often work multiple jobs, yet still find it difficult to meet daily expenses for food, school fees, and shelter. This fundraiser aims to distribute livelihood starter kits such as sewing machines, sari-sari store packages, and small capital for food vending. The goal is to empower single mothers by giving them the tools they need to start or sustain a source of income. With proper training and follow-up support from local volunteers, these mothers can achieve financial independence and stability. Every donation will directly support the purchase of livelihood packages, training materials, and mentoring sessions. By supporting this initiative, you are not just giving money—you are investing in sustainable solutions for struggling families. Together, we can uplift single mothers, strengthen communities, and provide a brighter future for their children. Your generosity will truly change lives.', 'Livelihood Support', NULL, 'Single mothers from Barangay San Isidro', '100000.00', NULL, 'Active', '2025-09-01 10:15:00', NULL, 202504, NULL, NULL, 0, NULL);
INSERT INTO `fundraisers` (`fund_id`, `fund_title`, `fund_desc`, `fund_category`, `fund_img`, `fund_beneficiary`, `fund_goalamount`, `fund_link`, `fund_status`, `fund_startdate`, `fund_enddate`, `fund_creatorid`, `blockchain_fund_id`, `blockchain_tx_hash`, `blockchain_verified`, `creator_wallet_address`) VALUES
(20252604, 'School Supplies for Flood-Affected Kids', 'When Typhoon Carina hit our town, hundreds of children were left without their school supplies. Families lost books, notebooks, pens, and even school uniforms due to flooding that damaged their homes. This fundraiser aims to provide essential educational materials for students so they can continue learning despite the disaster. Education is one of the first steps toward recovery, and having the right supplies helps children regain a sense of normalcy and hope. Every peso raised will go directly to purchasing notebooks, writing tools, school bags, and uniforms for affected children. Volunteers will also conduct small learning activities and distribute the supplies to families in evacuation centers. By contributing to this cause, you are not just giving materials—you are also restoring dignity and opportunities for children who deserve to dream again. Together, let us make sure no child is left behind after this calamity. Your support, no matter how small, will make a big difference in their education and future.', 'Disaster Relief', , 'Children affected by Typhoon Carina in Pila, Laguna', '50000.00', NULL, 'Active', '2025-09-10 09:00:00', NULL, 202504, NULL, NULL, 0, NULL);
INSERT INTO `fundraisers` (`fund_id`, `fund_title`, `fund_desc`, `fund_category`, `fund_img`, `fund_beneficiary`, `fund_goalamount`, `fund_link`, `fund_status`, `fund_startdate`, `fund_enddate`, `fund_creatorid`, `blockchain_fund_id`, `blockchain_tx_hash`, `blockchain_verified`, `creator_wallet_address`) VALUES
(20252605, 'Community Feeding Program for Malnourished Kids', 'Malnutrition remains one of the biggest challenges in our barangay, with many children going to school hungry and unable to focus on their lessons. This fundraiser seeks to provide daily meals for at least 150 children in the community for a period of three months. Nutritious food such as rice, vegetables, eggs, and fortified milk will be prepared by volunteer cooks and served in the local community center. Beyond simply filling stomachs, the feeding program also aims to teach families about affordable healthy cooking and nutrition practices. Through regular monitoring, we will track improvements in the children’s weight, energy levels, and school performance. Every peso donated will go toward purchasing food ingredients, cooking supplies, and covering basic logistical costs. We believe that no child should suffer or fall behind in school due to hunger. With your help, we can give them the nourishment they deserve, along with a healthier and brighter future. This is more than just a feeding program—it is a step toward building a stronger, healthier community for everyone.', 'Community', NULL, '150 undernourished children in Barangay Mabini', '75000.00', NULL, 'Active', '2025-09-05 08:00:00', NULL, 202504, NULL, NULL, 0, NULL);
INSERT INTO `fundraisers` (`fund_id`, `fund_title`, `fund_desc`, `fund_category`, `fund_img`, `fund_beneficiary`, `fund_goalamount`, `fund_link`, `fund_status`, `fund_startdate`, `fund_enddate`, `fund_creatorid`, `blockchain_fund_id`, `blockchain_tx_hash`, `blockchain_verified`, `creator_wallet_address`) VALUES
(20252606, 'Shelter Repair for Typhoon Survivors', 'After the devastating impact of the recent typhoon, many families in our town are left without safe and secure housing. Roofs were blown away, walls collapsed, and some houses were completely destroyed. This fundraiser aims to provide shelter repair kits including GI sheets, nails, plywood, and other construction materials for at least 50 affected families. Volunteers and local carpenters will assist in rebuilding and repairing homes to ensure families are safe before the rainy season intensifies again. Each family will receive enough materials to rebuild essential parts of their homes, especially roofs and walls. Aside from immediate shelter, this initiative helps restore dignity and stability to people who have lost almost everything. Every contribution, big or small, will help bring hope back to these households. Together, we can ensure that families will not be left in the cold or exposed to the elements. Let us rebuild not just houses, but lives filled with safety and resilience.', 'Disaster Relief', , '50 displaced families from Typhoon Elina', '200000.00', NULL, 'Active', '2025-09-12 11:20:00', NULL, 202504, NULL, NULL, 0, NULL);
INSERT INTO `fundraisers` (`fund_id`, `fund_title`, `fund_desc`, `fund_category`, `fund_img`, `fund_beneficiary`, `fund_goalamount`, `fund_link`, `fund_status`, `fund_startdate`, `fund_enddate`, `fund_creatorid`, `blockchain_fund_id`, `blockchain_tx_hash`, `blockchain_verified`, `creator_wallet_address`) VALUES
(20252607, 'Medical Assistance for Lola Maria', 'Lola Maria is a 72-year-old grandmother who has been diagnosed with chronic kidney disease requiring regular dialysis sessions. Unfortunately, her family cannot keep up with the high costs of treatment. Each session costs thousands of pesos, and she needs multiple sessions every week. Aside from dialysis, she also requires expensive maintenance medicines, frequent laboratory tests, and transportation support to and from the hospital. Her children, who are minimum-wage earners, already struggle to provide for their own families. Without financial help, it will be impossible for Lola Maria to continue her treatments, putting her life at risk. This fundraiser is dedicated to covering her medical expenses so she can continue her dialysis and live comfortably despite her condition. Every donation will go directly to her hospital bills, medications, and transportation allowance. By extending your help, you are giving Lola Maria the gift of more time with her grandchildren and loved ones. Let us give her the chance to live her remaining years with dignity and love.', 'Medical', NULL, 'Maria Santos (72 years old)', '180000.00', NULL, 'Active', '2025-08-30 16:45:00', NULL, 202504, NULL, NULL, 0, NULL),
(20252608, 'Animal Rescue Center Supplies Drive', 'Our local animal rescue center is currently sheltering over 60 abandoned and stray dogs and cats. With the recent increase in rescued animals, the shelter is facing shortages in food, medicine, and cleaning supplies. This fundraiser aims to provide sufficient resources for the shelter to continue operating effectively and caring for the animals. Donations will be used to purchase dog and cat food, vitamins, anti-rabies vaccines, cages, and cleaning materials. Additionally, part of the funds will support spay and neuter programs to control stray animal populations in the area. Volunteers will also be trained to help with proper animal handling, fostering, and adoption drives. Every donation ensures that these animals receive the love, care, and shelter they deserve. Together, we can give abandoned animals a second chance at life and a forever home. Supporting this campaign means extending compassion not just to pets, but to the entire community that benefits from responsible animal care.', 'Animal Rescue & Welfare', NULL, 'Stray dogs and cats in San Pedro Animal Rescue Center', '60000.00', NULL, 'Active', '2025-09-03 13:10:00', NULL, 202504, NULL, NULL, 0, NULL);
INSERT INTO `fundraisers` (`fund_id`, `fund_title`, `fund_desc`, `fund_category`, `fund_img`, `fund_beneficiary`, `fund_goalamount`, `fund_link`, `fund_status`, `fund_startdate`, `fund_enddate`, `fund_creatorid`, `blockchain_fund_id`, `blockchain_tx_hash`, `blockchain_verified`, `creator_wallet_address`) VALUES
(20252609, 'Kidney Transplant Needs', 'A 35-year-old individual is facing a life-changing health challenge that requires urgent medical attention. After being diagnosed with severe kidney disease, their condition has worsened to the point where a kidney transplant is the only viable option for survival. This individual has been battling health issues for several years, undergoing numerous treatments that have significantly impacted their quality of life.\r\n\r\nDespite their resilience and determination, the financial burden of the necessary medical procedures and post-operative care is overwhelming. The estimated cost for the kidney transplant, including hospital fees, medications, and follow-up treatments, amounts to ₱90,000. This financial need arises not only from the surgery itself but also from the extensive care required during recovery, which includes regular check-ups, medications to prevent organ rejection, and potential complications that may arise.\r\n\r\nFamily and friends have been supportive throughout this difficult journey, but the cumulative costs have exceeded what can be reasonably covered without additional help. This individual remains hopeful for a brighter future and is committed to returning to a normal life where they can be active and engaged with their loved ones once again.\r\n\r\nContributions to this fundraiser will directly support the medical expenses associated with the kidney transplant, allowing for the chance of a new beginning and the opportunity to reclaim health and well-being. Every donation, no matter the size, can make a significant difference in this individual’s fight for life.', 'Medical', , 'Yourself', '90000.00', 'generated-link', 'Active', '2025-09-25 18:13:15', NULL, 202503, NULL, NULL, 0, NULL);
INSERT INTO `fundraisers` (`fund_id`, `fund_title`, `fund_desc`, `fund_category`, `fund_img`, `fund_beneficiary`, `fund_goalamount`, `fund_link`, `fund_status`, `fund_startdate`, `fund_enddate`, `fund_creatorid`, `blockchain_fund_id`, `blockchain_tx_hash`, `blockchain_verified`, `creator_wallet_address`) VALUES
(20252610, 'Fight Against Parvo: Help Save Our Furry Friends', 'Parvovirus, commonly known as parvo, is a highly contagious viral disease that severely affects dogs, particularly puppies and unvaccinated dogs. It attacks the gastrointestinal tract and can lead to severe dehydration, vomiting, and ultimately, death if not treated promptly. Many furry companions in the community are at risk, and the current situation has become alarming as several dogs are being diagnosed and require urgent medical care.\r\n\r\nThe funds raised through this campaign will be directed towards providing life-saving treatment for dogs suffering from parvo. This includes necessary veterinary visits, hospitalization, intravenous fluids, medications, and supportive care that can amount to significant expenses. Each treatment can cost thousands of pesos, and with the increasing number of cases, the need for financial support has never been greater.\r\n\r\nIn addition to immediate medical care, the fundraiser aims to raise awareness about the importance of vaccination and preventive measures against parvo. Educating the community can help reduce the number of new cases and protect vulnerable pets from this devastating illness. By contributing, supporters will play a crucial role in not only saving lives but also fostering a safer environment for all dogs.\r\n\r\nEvery donation, no matter the size, will bring hope to those furry friends in need and assist in building a community that prioritizes the health and well-being of its pets. The goal is set at ₱30,000, which will ensure that several dogs receive the urgent care they desperately need to overcome this life-threatening disease. Your support can make a significant impact in the fight against parvo and help restore the joy that these beloved pets bring to their families.', 'Animal Rescue & Welfare', NULL, 'Yourself', '30000.00', 'generated-link', 'Active', '2025-09-28 18:03:21', NULL, 202502, NULL, NULL, 0, NULL),
(20252611, 'Fundraiser for Joshua\'s Asthma Treatment', 'Joshua is a beloved companion animal in need of urgent medical assistance due to a severe asthma condition. Recently diagnosed, he has been suffering from significant respiratory issues that require specialized treatment and ongoing care to manage his condition effectively. The team of veterinarians has recommended a comprehensive treatment plan involving medication, regular check-ups, and possibly emergency interventions.\r\n\r\nThis fundraiser seeks to raise ₱100,000 to cover the costs associated with Joshua\'s medical care. The funds will be allocated towards necessary medications, veterinary consultations, and other essential resources that will ensure he can breathe easier and enjoy a better quality of life. Without this financial support, the risk of serious health complications increases, which could threaten his well-being.\r\n\r\nJoshua is not just an animal; he is a cherished member of the family, bringing joy and companionship to those around him. His playful spirit and loving nature have touched the lives of many, making it crucial to provide him with the care he desperately needs. Contributions to this fundraiser will directly impact Joshua\'s health and future, enabling him to continue to be a source of happiness for his family and friends. Every donation, no matter the size, will play a part in helping Joshua overcome this challenging health crisis.', 'Animal Rescue & Welfare', NULL, 'Yourself', '100000.00', 'generated-link', 'Completed', '2025-09-30 12:53:14', NULL, 202502, NULL, NULL, 0, NULL);
INSERT INTO `fundraisers` (`fund_id`, `fund_title`, `fund_desc`, `fund_category`, `fund_img`, `fund_beneficiary`, `fund_goalamount`, `fund_link`, `fund_status`, `fund_startdate`, `fund_enddate`, `fund_creatorid`, `blockchain_fund_id`, `blockchain_tx_hash`, `blockchain_verified`, `creator_wallet_address`) VALUES
(20252612, 'Support Aplaya Evacuees Seeking Shelter', 'In recent weeks, the community of Aplaya has faced devastating circumstances due to severe weather conditions that have led to widespread flooding and displacement. Many families have lost their homes and possessions, forcing them into temporary shelters where basic necessities are scarce. The urgency of the situation has prompted local organizations to mobilize and provide immediate assistance, but the need for additional support remains critical.\n\nThe funds raised through this initiative will directly assist those affected by the disaster, helping to provide essential resources such as food, clean water, medical supplies, and temporary housing. The goal is to raise ₱50,000 to ensure that evacuees can receive the support they need to rebuild their lives and restore a sense of security in the aftermath of this calamity.\n\nEvery contribution, no matter the size, will make a significant impact on the lives of those affected in Aplaya. By pooling resources, the community can work together to provide a lifeline to families who are currently facing uncertainty and hardship. This effort not only addresses immediate needs but also fosters a spirit of solidarity and resilience among those impacted by this disaster.', 'Disaster Relief', , 'People Power Volunteers for Reform - Pila', '50000.00', 'generated-link', 'Active', '2025-10-01 15:06:30', NULL, 202502, NULL, NULL, 0, NULL);
INSERT INTO `fundraisers` (`fund_id`, `fund_title`, `fund_desc`, `fund_category`, `fund_img`, `fund_beneficiary`, `fund_goalamount`, `fund_link`, `fund_status`, `fund_startdate`, `fund_enddate`, `fund_creatorid`, `blockchain_fund_id`, `blockchain_tx_hash`, `blockchain_verified`, `creator_wallet_address`) VALUES
(20252613, 'Support for the Sale of Realme C30S to Fundraise', 'We are reaching out to the community to help support a fundraiser aimed at assisting individuals in need. The funds raised from the sale of a brand new Realme C30S (2/32GB) mobile phone will be directed towards helping those who are currently facing financial difficulties. This phone, which is in pristine condition and has no issues, is being offered at a very affordable price of 2,000 PHP.\n\nThis fundraiser is not just about selling a phone; it\'s about giving back to those who need it the most. Many individuals and families are struggling due to unforeseen circumstances, and every little bit counts. By purchasing this phone, you are not only getting a great deal but also contributing to a noble cause.\n\nThe funds raised will go towards providing basic necessities for families in need, including food, shelter, and medical supplies. Your support can truly make a difference in someone\'s life. We believe in the power of community, and together, we can create a positive impact.\n\nPlease consider purchasing this phone or sharing this post with your friends and family. Every share and every purchase helps us reach our goal and extends a helping hand to those in need. Thank you for your generosity and support!', 'Other', NULL, 'Emergency Relief', '2000.00', 'https://www.facebook.com/groups/571766703572232', 'Pending', '2025-10-13 11:03:48', NULL, 202504, NULL, NULL, 0, NULL),
(20252614, 'Support CVM Finance\'s Pension Loan Program', 'CVM Finance is reaching out to the community during this challenging BER months season. As many individuals are struggling financially, we are offering a pension loan program designed to provide quick financial relief. This initiative is aimed at helping those in need, ensuring that they can cover essential expenses and alleviate financial stress during this time of year.\n\nWith fast approval and immediate cash release, our pension loan program is an excellent opportunity for those who require urgent assistance. We understand that these months can be particularly tough for families and individuals, and our goal is to support our community by providing accessible financial services. CVM Finance is committed to ensuring that every individual feels supported and can navigate their financial challenges with ease.\n\nYour contributions can make a significant difference in the lives of many. By supporting our fundraiser, you are helping us extend our reach and assist more individuals in securing the funds they need. Every donation, no matter how small, helps us achieve our goal of providing financial assistance to those who are struggling.\n\nLet us come together as a community to support one another during this time. Your generosity can help us ensure that everyone can celebrate the holidays without the burden of financial strain. Thank you for considering a donation to our pension loan program at CVM Finance.', 'Other', NULL, 'Emergency Relief', '50000.00', 'https://www.facebook.com/groups/3408312342792580', 'Pending', '2025-10-13 11:03:48', NULL, 202504, NULL, NULL, 0, NULL);
INSERT INTO `fundraisers` (`fund_id`, `fund_title`, `fund_desc`, `fund_category`, `fund_img`, `fund_beneficiary`, `fund_goalamount`, `fund_link`, `fund_status`, `fund_startdate`, `fund_enddate`, `fund_creatorid`, `blockchain_fund_id`, `blockchain_tx_hash`, `blockchain_verified`, `creator_wallet_address`) VALUES
(20252615, 'Community Support for Families in Labuin After the Typhoon', 'Barangay Labuin was among the areas hit hardest by the recent typhoon, leaving many homes damaged and several families struggling with limited access to clean water, food, and hygiene supplies. The strong winds tore off roofs, flooded streets, and caused electrical outages that lasted for days. Even now, many residents are still facing the aftermath, trying to navigate daily life while dealing with lost belongings, damaged houses, and unstable living conditions.\r\n\r\nFor families who lost everything in a single night, the road to recovery feels overwhelming. Parents are doing their best to stay strong for their children, but the reality of needing food, clean water, clothing, and shelter weighs heavily on them. Some households are staying with relatives, while others rely on temporary evacuation areas that are already crowded and lacking resources. Without outside support, it becomes difficult for them to meet even the most basic needs.\r\n\r\nThis campaign was created to extend real, immediate help to these families. Every contribution goes toward relief packs, drinking water, blankets, and essential medical items. These supplies are crucial not only for survival, but also for restoring comfort and dignity during a time when hope can easily fade. With your help, we can reach more households, provide sustained assistance, and remind affected residents that they are not alone in this struggle.\r\n\r\nYour support will make a meaningful difference. By standing with the people of Labuin, you help them rebuild their homes, protect their families, and move forward with renewed strength and confidence. Together, we can turn a moment of crisis into an opportunity for compassion, unity, and healing.', 'Disaster Relief', , 'Yourself', '60000.00', 'generated-link', 'Active', '2025-12-02 08:45:41', NULL, 202503, NULL, NULL, 0, NULL);
INSERT INTO `fundraisers` (`fund_id`, `fund_title`, `fund_desc`, `fund_category`, `fund_img`, `fund_beneficiary`, `fund_goalamount`, `fund_link`, `fund_status`, `fund_startdate`, `fund_enddate`, `fund_creatorid`, `blockchain_fund_id`, `blockchain_tx_hash`, `blockchain_verified`, `creator_wallet_address`) VALUES
(20252616, 'Helping Fire-Affected Families in Bagong Pook, Pila Laguna', 'Bagong Pook, a vibrant barangay in Pila, Laguna, recently experienced a tragic house fire that swept through several homes late at night. Dozens of families lost not only their houses but all their personal belongings — clothes, important documents, appliances, and everyday essentials were destroyed in the blaze. Many of those affected are hardworking families who depend on modest daily incomes, leaving them with no capacity to rebuild on their own.\r\n\r\nIn the aftermath, parents and children are scrambling just to meet their most basic needs. Some families are temporarily staying with relatives, while others are living in cramped evacuation shelters with limited amenities. The emotional toll is heavy, especially for children who lost their rooms, toys, and school supplies overnight. With no savings and no immediate source of support, these households are vulnerable and uncertain about how to move forward.\r\n\r\nThis fundraising campaign aims to raise resources for immediate relief: food packs, clean water, clothing, hygiene kits, blankets, basic kitchen items, and temporary shelter aids. Further, funds will help purchase materials needed to rebuild or repair destroyed houses — roofing materials, lumber, and tools — so families can return to safe, stable homes as soon as possible. Each donation brings hope and concrete help to those who lost everything.\r\n\r\nYour support can transform despair into resilience. By contributing, you help restore dignity, safety, and a sense of normalcy for families in Bagong Pook. Together, we can give them the fresh start they desperately need.', 'Disaster Relief', , 'Yourself', '60000.00', 'generated-link', 'Active', '2025-12-02 08:58:37', NULL, 202502, NULL, NULL, 0, NULL);
INSERT INTO `fundraisers` (`fund_id`, `fund_title`, `fund_desc`, `fund_category`, `fund_img`, `fund_beneficiary`, `fund_goalamount`, `fund_link`, `fund_status`, `fund_startdate`, `fund_enddate`, `fund_creatorid`, `blockchain_fund_id`, `blockchain_tx_hash`, `blockchain_verified`, `creator_wallet_address`) VALUES
(20252617, 'Support Earthquake Victims in San Antonio: Help Rebuild Lives', 'In the wake of a devastating earthquake that struck Bagong Pook in Pila, Laguna, numerous families have found themselves displaced and facing dire circumstances. This natural disaster has caused significant destruction to homes and infrastructure, leaving many without shelter, basic necessities, and access to vital resources. The impact of the earthquake has been profound, with entire communities grappling to rebuild their lives amidst the chaos.\r\n\r\nMany families have lost their homes, personal belongings, and sources of income, plunging them into a state of uncertainty and distress. The aftermath of such a disaster often results in a pressing need for immediate assistance, as the affected individuals struggle to secure food, clean water, clothing, and medical care. The emotional toll on these families is immense, as they navigate the challenges of recovery and the loss of stability.\r\n\r\nThe goal of this fundraiser is to raise ₱120,000, which will directly support the affected families in Bagong Pook. The funds will be utilized to provide essential supplies, temporary shelter, and basic healthcare services to those in need. By contributing to this cause, individuals can play a crucial role in helping these families regain a sense of normalcy and rebuild their lives after this traumatic event.\r\n\r\nEvery donation, no matter the size, will make a significant difference in the lives of those impacted by the earthquake. This initiative aims to foster a spirit of community support and resilience, ensuring that the affected families receive the assistance they urgently require during this challenging time.', 'Disaster Relief', , NULL, '120000.00', 'generated-link', 'Active', '2025-12-02 11:06:14', NULL, 202503, NULL, NULL, 0, NULL);

