--
-- Structure for view `blockchain_transaction_summary`
--
DROP TABLE IF EXISTS `blockchain_transaction_summary`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `blockchain_transaction_summary`  AS SELECT `bt`.`transaction_type` AS `transaction_type`, `bt`.`status` AS `status`, count(0) AS `transaction_count`, sum(`bt`.`gas_used`) AS `total_gas_used`, avg(`bt`.`gas_used`) AS `avg_gas_used`, min(`bt`.`created_at`) AS `earliest_transaction`, max(`bt`.`created_at`) AS `latest_transaction` FROM `blockchain_transactions` AS `bt` GROUP BY `bt`.`transaction_type`, `bt`.`status`;

-- --------------------------------------------------------

--
-- Structure for view `donation_verification_status`
--
DROP TABLE IF EXISTS `donation_verification_status`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `donation_verification_status`  AS SELECT `d`.`don_id` AS `don_id`, `d`.`don_refnum` AS `don_refnum`, `d`.`don_amount` AS `don_amount`, `d`.`don_status` AS `don_status`, `d`.`verification_status` AS `verification_status`, `d`.`blockchain_tx_hash` AS `blockchain_tx_hash`, `d`.`block_number` AS `block_number`, `f`.`fund_title` AS `fund_title`, `u`.`name` AS `donor_name`, `wa`.`wallet_address` AS `donor_wallet` FROM (((`donations` `d` left join `fundraisers` `f` on(`d`.`fund_id` = `f`.`fund_id`)) left join `users` `u` on(`d`.`don_donorid` = `u`.`id`)) left join `wallet_addresses` `wa` on(`u`.`id` = `wa`.`user_id` and `wa`.`is_primary` = 1))  ;

