--
-- Tampered-value preservation overrides for donations
-- Keeps original donation fields unchanged and stores attempted changes
-- in tampered_* columns instead.
--
ALTER TABLE `donations`
  ADD COLUMN IF NOT EXISTS `tampered_fund_id` INT(11) DEFAULT NULL AFTER `original_tx_hash`,
  ADD COLUMN IF NOT EXISTS `tampered_don_donorid` INT(11) DEFAULT NULL AFTER `tampered_fund_id`,
  ADD COLUMN IF NOT EXISTS `tampered_don_donorname` VARCHAR(80) DEFAULT NULL AFTER `tampered_don_donorid`,
  ADD COLUMN IF NOT EXISTS `tampered_don_receiver` VARCHAR(80) DEFAULT NULL AFTER `tampered_don_donorname`,
  ADD COLUMN IF NOT EXISTS `tampered_don_paymethod` VARCHAR(50) DEFAULT NULL AFTER `tampered_don_receiver`,
  ADD COLUMN IF NOT EXISTS `tampered_don_amount` DECIMAL(12,2) DEFAULT NULL AFTER `tampered_don_paymethod`,
  ADD COLUMN IF NOT EXISTS `tampered_don_refnum` VARCHAR(80) DEFAULT NULL AFTER `tampered_don_amount`,
  ADD COLUMN IF NOT EXISTS `tampered_don_date` DATETIME DEFAULT NULL AFTER `tampered_don_refnum`,
  ADD COLUMN IF NOT EXISTS `tampered_donor_wallet_address` VARCHAR(42) DEFAULT NULL AFTER `tampered_don_date`;

DROP TRIGGER IF EXISTS `trg_donation_tamper_bi`;
DROP TRIGGER IF EXISTS `trg_donation_tamper_bu`;

DELIMITER $$
CREATE TRIGGER `trg_donation_tamper_bi`
BEFORE INSERT ON `donations`
FOR EACH ROW
BEGIN
  SET NEW.`is_tampered` = 0;
  SET NEW.`tampered_fund_id` = NULL;
  SET NEW.`tampered_don_donorid` = NULL;
  SET NEW.`tampered_don_donorname` = NULL;
  SET NEW.`tampered_don_receiver` = NULL;
  SET NEW.`tampered_don_paymethod` = NULL;
  SET NEW.`tampered_don_amount` = NULL;
  SET NEW.`tampered_don_refnum` = NULL;
  SET NEW.`tampered_don_date` = NULL;
  SET NEW.`tampered_donor_wallet_address` = NULL;
END
$$
DELIMITER ;

DELIMITER $$
CREATE TRIGGER `trg_donation_tamper_bu`
BEFORE UPDATE ON `donations`
FOR EACH ROW
BEGIN
  DECLARE attempted_tamper TINYINT(1) DEFAULT 0;

  IF NOT (OLD.`fund_id` <=> NEW.`fund_id`) THEN
    SET NEW.`tampered_fund_id` = NEW.`fund_id`;
    SET NEW.`fund_id` = OLD.`fund_id`;
    SET attempted_tamper = 1;
  END IF;

  IF NOT (OLD.`don_donorid` <=> NEW.`don_donorid`) THEN
    SET NEW.`tampered_don_donorid` = NEW.`don_donorid`;
    SET NEW.`don_donorid` = OLD.`don_donorid`;
    SET attempted_tamper = 1;
  END IF;

  IF NOT (OLD.`don_donorname` <=> NEW.`don_donorname`) THEN
    SET NEW.`tampered_don_donorname` = NEW.`don_donorname`;
    SET NEW.`don_donorname` = OLD.`don_donorname`;
    SET attempted_tamper = 1;
  END IF;

  IF NOT (OLD.`don_paymethod` <=> NEW.`don_paymethod`) THEN
    SET NEW.`tampered_don_paymethod` = NEW.`don_paymethod`;
    SET NEW.`don_paymethod` = OLD.`don_paymethod`;
    SET attempted_tamper = 1;
  END IF;

  IF NOT (OLD.`don_amount` <=> NEW.`don_amount`) THEN
    SET NEW.`tampered_don_amount` = NEW.`don_amount`;
    SET NEW.`don_amount` = OLD.`don_amount`;
    SET attempted_tamper = 1;
  END IF;

  IF NOT (OLD.`don_refnum` <=> NEW.`don_refnum`) THEN
    SET NEW.`tampered_don_refnum` = NEW.`don_refnum`;
    SET NEW.`don_refnum` = OLD.`don_refnum`;
    SET attempted_tamper = 1;
  END IF;

  IF NOT (OLD.`don_date` <=> NEW.`don_date`) THEN
    SET NEW.`tampered_don_date` = NEW.`don_date`;
    SET NEW.`don_date` = OLD.`don_date`;
    SET attempted_tamper = 1;
  END IF;

  IF NOT (OLD.`donor_wallet_address` <=> NEW.`donor_wallet_address`) THEN
    SET NEW.`tampered_donor_wallet_address` = NEW.`donor_wallet_address`;
    SET NEW.`donor_wallet_address` = OLD.`donor_wallet_address`;
    SET attempted_tamper = 1;
  END IF;

  IF COALESCE(OLD.`is_tampered`, 0) = 1 OR attempted_tamper = 1 THEN
    SET NEW.`is_tampered` = 1;
  ELSE
    SET NEW.`is_tampered` = 0;
  END IF;

  SET NEW.`donation_row_hash` = fn_donation_row_hash_v1(
    NEW.`don_id`,
    NEW.`fund_id`,
    NEW.`don_donorid`,
    NEW.`don_donorname`,
    NEW.`don_receiver`,
    NEW.`don_paymethod`,
    NEW.`don_amount`,
    NEW.`don_refnum`,
    NEW.`don_status`,
    NEW.`don_date`,
    NEW.`don_notes`,
    NEW.`blockchain_tx_hash`,
    NEW.`block_number`,
    NEW.`gas_used`,
    NEW.`verification_status`,
    NEW.`verification_date`,
    NEW.`donor_wallet_address`,
    NEW.`recorded_by_admin`
  );
END
$$
DELIMITER ;
